// n8n expects an array of objects as output

const now = new Date();

// Define the free slots: Monday, Wednesday, Friday at 3:00 PM
// JavaScript Date: 0=Sunday, 1=Monday, ..., 5=Friday, 6=Saturday
const slots = [
  { day: 1, hour: 15 }, // Monday 3 PM
  { day: 3, hour: 15 }, // Wednesday 3 PM
  { day: 5, hour: 15 }, // Friday 3 PM
];

// Helper to get the next slot after 'now', always in the future (never today)
function getNextSlot(now, slots) {
  let minDiff = Infinity;
  let nextSlotDate = null;

  for (const slot of slots) {
    let daysUntil = (slot.day - now.getDay() + 7) % 7;
    // Always skip today, even if the slot time hasn't passed
    if (daysUntil === 0) {
      daysUntil = 7;
    }

    const slotDate = new Date(
      now.getFullYear(),
      now.getMonth(),
      now.getDate() + daysUntil,
      slot.hour,
      0,
      0,
      0
    );

    if (slotDate - now < minDiff) {
      minDiff = slotDate - now;
      nextSlotDate = slotDate;
    }
  }

  return nextSlotDate;
}

// Format as "YYYY-MM-DD HH:MM:SS"
function formatDate(date) {
  const pad = (n) => n.toString().padStart(2, '0');
  return (
    date.getFullYear() +
    '-' +
    pad(date.getMonth() + 1) +
    '-' +
    pad(date.getDate()) +
    ' ' +
    pad(date.getHours()) +
    ':00:00'
  );
}

const nextSlot = getNextSlot(now, slots);

// Create the end time (1 hour after start)
const endSlot = new Date(nextSlot.getTime() + 60 * 60 * 1000);

return [
  {
    json: {
      nextSlot: formatDate(nextSlot),
      endSlot: formatDate(endSlot)
    }
  }
];
